def _order_field_to_sql(self, alias, field_name, direction, nulls, query):
    if field_name == 'last_access_date_group':
        self.env['documents.access'].flush_model(['last_access_date', 'partner_id', 'document_id'])
        sql_field = SQL(
            "SELECT last_access_date FROM documents_access WHERE partner_id = %s AND document_id = %s",
            SQL.identifier(alias, 'id')
        )
        return SQL("(%s) %s %s", sql_field, direction, nulls)
    if field_name == 'is_folder':
        # reverse the order
        sql_field = self._field_to_sql(alias, field_name, query)
        return SQL("NOT (%s) %s %s", sql_field, direction, nulls)
    return super()._order_field_to_sql(alias, field_name, direction, nulls, query)

